class Solution:
    def numberOfPaths(self, grid, k):
        MOD = 10**9 + 7
        m, n = len(grid), len(grid[0])
        count = 0
        # enumerate every down/right path explicitly (feasible only for small grids)
        def walk(i, j, s):
            nonlocal count
            s += grid[i][j]
            if i == m - 1 and j == n - 1:
                if s % k == 0:
                    count += 1
                return
            if i + 1 < m:
                walk(i + 1, j, s)
            if j + 1 < n:
                walk(i, j + 1, s)
        walk(0, 0, 0)
        return count % MOD

