class Solution:
    def numberOfPaths(self, grid, k):
        MOD = 10**9 + 7
        m, n = len(grid), len(grid[0])
        dp = [[[0] * k for _ in range(n)] for _ in range(m)]
        dp[0][0][grid[0][0] % k] = 1
        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                v = grid[i][j] % k
                cur = dp[i][j]
                for r in range(k):
                    total = 0
                    pr = (r - v) % k
                    if i > 0:
                        total += dp[i - 1][j][pr]
                    if j > 0:
                        total += dp[i][j - 1][pr]
                    cur[r] = total % MOD
        return dp[m - 1][n - 1][0] % MOD

