var numberOfPaths = function(grid, k) {
    const MOD = 1000000007n;
    const m = grid.length, n = grid[0].length;
    const dp = Array.from({ length: m }, () =>
        Array.from({ length: n }, () => new Array(k).fill(0n)));
    dp[0][0][grid[0][0] % k] = 1n;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (i === 0 && j === 0) continue;
            const v = grid[i][j] % k;
            for (let r = 0; r < k; r++) {
                let total = 0n;
                const pr = ((r - v) % k + k) % k;
                if (i > 0) total += dp[i - 1][j][pr];
                if (j > 0) total += dp[i][j - 1][pr];
                dp[i][j][r] = total % MOD;
            }
        }
    }
    return Number(dp[m - 1][n - 1][0] % MOD);
};
